#include <stdio.h>
int main()
{
	int n,m,c=0;
	scanf("%d%d",&n,&m);
	while(n<m)
	{
		if(!(m%2))
		{
			m/=2;
			c++;
		}
		else
		{
			m++;
			c++;
		}
	}
	while(n>m)
	{
		n--;
		c++;
	}
	printf("%d",c);
	return 0;
}

