use std::io::stdin;
use std::collections::VecDeque;

macro_rules! input{
    ( $s: expr, $t:ty ) => {
        {
            $s.clear();
            let mut _stdin = stdin();
            _stdin.read_line(&mut $s).unwrap();
            $s.trim().parse::<$t>().unwrap()
        }
    };
    ( $s: expr, $($t:ty),* ) => {
        {
            $s.clear();
            let mut _stdin = stdin();
            _stdin.read_line(&mut $s).unwrap();
            let mut iterator = $s.trim().split_whitespace();
            let result = ($(iterator.next().unwrap().parse::<$t>().unwrap(),)*);
            assert!(iterator.next().is_none());
            result
        }
    };
}

const LIM: usize = 20001;

fn main() {
    let mut s = String::new();
    let (n, m) = input!(s, usize, usize);

    let mut memo = vec![-1; LIM];
    let mut queue = VecDeque::new();
    memo[n] = 0;
    queue.push_back(n);
    while let Some(i) = queue.pop_front() {
        if memo[m] != -1 {
            println!("{}", memo[m]);
            return;
        }
        if 2 * i < LIM && memo[2 * i] == -1 {
            queue.push_back(2 * i);
            memo[2 * i] = memo[i] + 1;
        }
        if i > 0 && memo[i - 1] == -1 {
            queue.push_back(i - 1);
            memo[i - 1] = memo[i] + 1;
        }
    }
}
